mapper.select:
SELECT DISTINCT cdg.`id`, cdg.`name`, cdg.`pid`, cdg.`level`, cdg.`node_type`, cdg.`type`, cdg.`mode`, cdg.`info`, cdg.`create_by`, cdg.`create_time`, cdg.`scheduler_fire_instance_id`, cdg.`sync_status`, cdg.`update_by`, cdg.`last_update_time`, #{visualizationId} as visualizationId FROM core_dataset cdg INNER JOIN core_chart_view_snapshot ccv ON cdg.id = ccv.table_id AND ccv.type != 'VQuery' INNER JOIN core_visualization_snapshot dvi ON ccv.scene_id = dvi.id WHERE ccv.scene_id = #{visualizationId} AND dvi.id = #{visualizationId}
AND INSTR(dvi.component_data, TO_CHAR(ccv.id)) > 0
AND LOCATE( ccv.id, dvi.component_data)

SELECT DISTINCT ccv.id as chartId,ccv.title as chartName,ccv.type as chartType FROM core_chart_view_snapshot ccv INNER JOIN core_visualization_snapshot dvi ON ccv.scene_id = dvi.id WHERE ccv.table_id = #{dataset_group_id} AND ccv.type != 'VQuery' AND dvi.id = #{visualizationId}
AND INSTR(dvi.component_data, TO_CHAR(ccv.id)) > 0
AND LOCATE(ccv.id, dvi.component_data)
